#!/usr/bin/env node
/**
 * scripts/delete-outlet-collections.mjs
 *
 * One-shot, idempotent script to delete the legacy `outlet-*` collections
 * of the LedsC4 B2B shop, AFTER verifying that nothing in the theme or
 * shop references them.
 *
 * Background:
 *   The outlet-* hierarchy is legacy. The canon today is cat-* (created by
 *   setup-cat-collections.mjs + translated by register-cat-translations.mjs).
 *   The outlet-* padres still smart-collect products because their old rules
 *   match; their hijos are empty. Their FR/EN translations were generated by
 *   T&A and are contaminated (e.g. Forlight → "Pour la lumière"). If any
 *   surface in the storefront or admin links to /collections/outlet-*, the
 *   bug Albert saw earlier reappears. This script removes them — but only
 *   after a reference scan confirms it's safe.
 *
 * Flow:
 *   Step 1 — Inventory: list all outlet-* collections.
 *   Step 2 — Reference scan:
 *      - Theme files in this repo (sections, snippets, templates, layout,
 *        config, locales, assets).
 *      - Shop admin (Shop.metafields, menus, pages, articles, sampled
 *        product metafields).
 *   Step 3 — Decision:
 *      - If any reference found → abort with exit 1. NO deletes.
 *      - If clean → proceed.
 *   Step 4 — Execute:
 *      - DRY_RUN (default): print plan to stdout + delete-outlet-plan.json.
 *      - Execute (DRY_RUN=false): warn 5s, then collectionDelete per
 *        collection. Idempotent — re-running after success finds zero
 *        outlet-*.
 *
 * Safety:
 *   - DRY_RUN defaults to TRUE. Only DRY_RUN=false executes. Same convention
 *     as scripts/fix-translations.mjs.
 *   - 5-second sleep with stderr warning before the first delete mutation.
 *   - Reference scan blocks execution if anything links to outlet-*.
 *
 * Requirements:
 *   - Env: SHOPIFY_STORE_DOMAIN, SHOPIFY_ADMIN_TOKEN, SHOPIFY_API_VERSION
 *     (optional, default 2025-10). Same env contract as the rest of scripts/.
 *
 * Usage:
 *   node --env-file=shopify-ledsc4-theme.env scripts/delete-outlet-collections.mjs              # dry run
 *   DRY_RUN=false node --env-file=shopify-ledsc4-theme.env scripts/delete-outlet-collections.mjs   # execute
 */

import { readFile, readdir, writeFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import { dirname, resolve, join, relative } from 'node:path';

// -----------------------------------------------------------------------------
// Config
// -----------------------------------------------------------------------------

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, '..');

const SHOPIFY_STORE_DOMAIN = process.env.SHOPIFY_STORE_DOMAIN;
const TOKEN = process.env.SHOPIFY_ADMIN_TOKEN;
const API_VERSION = process.env.SHOPIFY_API_VERSION ?? '2025-10';

// IMPORTANT — DRY_RUN safety contract (mirror of scripts/fix-translations.mjs:35):
//   - Default is dry-run (no mutations).
//   - Only DRY_RUN=false (literal lowercase string) triggers EXECUTE.
//   - This script also adds a 5-second stderr warning before the first
//     delete mutation, so a fat-fingered DRY_RUN=false can still be aborted
//     with Ctrl+C.
const DRY_RUN = process.env.DRY_RUN !== 'false';

const PLAN_FILE = 'delete-outlet-plan.json';

const PRE_DELETE_WAIT_MS = 5000;

// Theme directories to scan locally for "outlet-" references. Same surface as
// the theme structure documented in CLAUDE.md and what `shopify theme push`
// uploads.
const THEME_DIRS = ['sections', 'snippets', 'templates', 'layout', 'config', 'locales', 'assets'];
const THEME_EXTENSIONS = new Set(['.liquid', '.json', '.js', '.css', '.svg']);

// Regex that captures outlet-handle-like strings: lowercase letters, digits,
// hyphens, starting with literal "outlet-". Anything that isn't a Shopify
// handle pattern (e.g. "Outlet Center" in marketing copy) won't match.
const OUTLET_HANDLE_PATTERN = /outlet-[a-z0-9-]+/gi;

// How many products to sample when scanning product metafields for outlet-*
// references. Full scan would be 700+ products × dozens of metafields each.
// 100 is enough to catch a systemic issue without blowing the API budget.
const PRODUCT_METAFIELD_SAMPLE = 100;

if (!SHOPIFY_STORE_DOMAIN || !TOKEN) {
  console.error('Missing env vars: SHOPIFY_STORE_DOMAIN and SHOPIFY_ADMIN_TOKEN are required.');
  console.error('Tip: invoke with `node --env-file=shopify-ledsc4-theme.env scripts/delete-outlet-collections.mjs`.');
  process.exit(1);
}

const ENDPOINT = `https://${SHOPIFY_STORE_DOMAIN}/admin/api/${API_VERSION}/graphql.json`;

// -----------------------------------------------------------------------------
// GraphQL client with cost-aware throttling (same pattern as the rest of scripts/)
// -----------------------------------------------------------------------------

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function gql(query, variables = {}, attempt = 0) {
  const res = await fetch(ENDPOINT, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-Shopify-Access-Token': TOKEN,
    },
    body: JSON.stringify({ query, variables }),
  });

  if (!res.ok) {
    if (res.status === 429 && attempt < 5) {
      const wait = 2000 * (attempt + 1);
      console.warn(`429 rate limited. Waiting ${wait}ms…`);
      await sleep(wait);
      return gql(query, variables, attempt + 1);
    }
    throw new Error(`HTTP ${res.status}: ${await res.text()}`);
  }

  const json = await res.json();

  if (json.errors) {
    const throttled = json.errors.some((e) => e.extensions?.code === 'THROTTLED');
    if (throttled && attempt < 5) {
      const wait = 2000 * (attempt + 1);
      console.warn(`THROTTLED. Waiting ${wait}ms…`);
      await sleep(wait);
      return gql(query, variables, attempt + 1);
    }
    throw new Error(`GraphQL errors: ${JSON.stringify(json.errors)}`);
  }

  const status = json.extensions?.cost?.throttleStatus;
  if (status && status.currentlyAvailable < 200) {
    const restoreNeeded = 500 - status.currentlyAvailable;
    const waitMs = Math.ceil((restoreNeeded / status.restoreRate) * 1000);
    if (waitMs > 0) {
      console.warn(`Low budget (${status.currentlyAvailable}/${status.maximumAvailable}). Waiting ${waitMs}ms…`);
      await sleep(waitMs);
    }
  }

  return json.data;
}

// -----------------------------------------------------------------------------
// Step 1 — Discover outlet-* collections
// -----------------------------------------------------------------------------

// Same defensive pattern as register-cat-translations.mjs. Shopify search
// rejects standalone `handle:outlet-*`; an explicit per-prefix wildcard
// covers the 5 known outlet padre slugs + their children + outlet-otros.
// If a future outlet-* exists with a different padre prefix, it won't be
// caught — which is the intended conservative behavior. The script reports
// the count and Dani can sanity-check against expectation (~20-44).
const OUTLET_COLLECTIONS_QUERY = /* GraphQL */ `
  query outletCollections($cursor: String) {
    collections(
      first: 50,
      query: "handle:outlet-forlight* OR handle:outlet-architectural* OR handle:outlet-decorative* OR handle:outlet-diy* OR handle:outlet-outdoor* OR handle:outlet-otros*",
      after: $cursor
    ) {
      pageInfo { hasNextPage endCursor }
      edges {
        node {
          id
          handle
          title
          productsCount { count }
          ruleSet { appliedDisjunctively rules { column relation condition } }
          resourcePublications(first: 10) {
            edges { node { publication { name id } } }
          }
        }
      }
    }
  }
`;

async function discoverOutletCollections() {
  const out = [];
  let cursor = null;
  while (true) {
    const data = await gql(OUTLET_COLLECTIONS_QUERY, { cursor });
    const conn = data.collections;
    for (const { node } of conn.edges) {
      out.push({
        id: node.id,
        handle: node.handle,
        title: node.title,
        productsCount: node.productsCount?.count ?? null,
        kind: (node.ruleSet?.rules?.length ?? 0) > 0 ? 'smart' : 'custom',
        publications: (node.resourcePublications?.edges ?? []).map((e) => e.node.publication.name),
      });
    }
    if (!conn.pageInfo.hasNextPage) break;
    cursor = conn.pageInfo.endCursor;
  }
  return out;
}

// -----------------------------------------------------------------------------
// Step 2a — Scan local theme files for outlet-* references
// -----------------------------------------------------------------------------

async function scanThemeFiles() {
  const hits = [];
  for (const dirName of THEME_DIRS) {
    const dirPath = join(REPO_ROOT, dirName);
    await scanDirRecursive(dirPath, hits);
  }
  return hits;
}

async function scanDirRecursive(dirPath, hits) {
  let entries;
  try {
    entries = await readdir(dirPath, { withFileTypes: true });
  } catch (e) {
    if (e.code === 'ENOENT') return; // directory may not exist (acceptable)
    throw e;
  }
  for (const entry of entries) {
    const full = join(dirPath, entry.name);
    if (entry.isDirectory()) {
      await scanDirRecursive(full, hits);
      continue;
    }
    if (!entry.isFile()) continue;
    const lastDot = entry.name.lastIndexOf('.');
    if (lastDot < 0) continue;
    const ext = entry.name.slice(lastDot).toLowerCase();
    if (!THEME_EXTENSIONS.has(ext)) continue;

    let content;
    try {
      content = await readFile(full, 'utf8');
    } catch (e) {
      console.warn(`  warning: cannot read ${full}: ${e.message}`);
      continue;
    }
    const lines = content.split(/\r?\n/);
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      OUTLET_HANDLE_PATTERN.lastIndex = 0;
      const matches = [...line.matchAll(OUTLET_HANDLE_PATTERN)];
      if (matches.length === 0) continue;
      for (const m of matches) {
        hits.push({
          source: 'theme-file',
          path: relative(REPO_ROOT, full).split('\\').join('/'),
          line: i + 1,
          match: m[0],
          context: line.trim().slice(0, 200),
        });
      }
    }
  }
}

// -----------------------------------------------------------------------------
// Step 2b — Scan shop admin resources for outlet-* references
// -----------------------------------------------------------------------------

const SHOP_METAFIELDS_QUERY = /* GraphQL */ `
  query shopMetafields($cursor: String) {
    shop {
      metafields(first: 100, after: $cursor) {
        pageInfo { hasNextPage endCursor }
        edges { node { namespace key value type } }
      }
    }
  }
`;

const MENUS_QUERY = /* GraphQL */ `
  query menus($cursor: String) {
    menus(first: 50, after: $cursor) {
      pageInfo { hasNextPage endCursor }
      edges {
        node {
          id
          title
          handle
          items {
            id
            title
            url
            type
            items {
              id
              title
              url
              type
              items { id title url type }
            }
          }
        }
      }
    }
  }
`;

const PAGES_QUERY = /* GraphQL */ `
  query pages($cursor: String) {
    pages(first: 100, after: $cursor) {
      pageInfo { hasNextPage endCursor }
      edges { node { id handle title body } }
    }
  }
`;

const ARTICLES_QUERY = /* GraphQL */ `
  query articles($cursor: String) {
    articles(first: 100, after: $cursor) {
      pageInfo { hasNextPage endCursor }
      edges { node { id handle title body } }
    }
  }
`;

const PRODUCTS_FOR_METAFIELD_SAMPLE_QUERY = /* GraphQL */ `
  query productsForMfSample($first: Int!) {
    products(first: $first, sortKey: UPDATED_AT, reverse: true) {
      edges {
        node {
          id
          handle
          metafields(first: 50) {
            edges { node { namespace key value type } }
          }
        }
      }
    }
  }
`;

function searchTextForOutlet(text, source, extra) {
  if (typeof text !== 'string' || text.length === 0) return [];
  const hits = [];
  OUTLET_HANDLE_PATTERN.lastIndex = 0;
  for (const m of text.matchAll(OUTLET_HANDLE_PATTERN)) {
    const idx = m.index ?? 0;
    const start = Math.max(0, idx - 40);
    const end = Math.min(text.length, idx + m[0].length + 40);
    hits.push({
      source,
      ...extra,
      match: m[0],
      context: text.slice(start, end).replace(/\s+/g, ' ').trim(),
    });
  }
  return hits;
}

async function scanShopMetafields() {
  const hits = [];
  let cursor = null;
  while (true) {
    const data = await gql(SHOP_METAFIELDS_QUERY, { cursor });
    const conn = data.shop.metafields;
    for (const { node } of conn.edges) {
      hits.push(...searchTextForOutlet(node.value, 'shop-metafield', {
        namespace: node.namespace, key: node.key,
      }));
    }
    if (!conn.pageInfo.hasNextPage) break;
    cursor = conn.pageInfo.endCursor;
  }
  return hits;
}

function flattenMenuItems(items, parentTrail = []) {
  const flat = [];
  for (const it of items ?? []) {
    const trail = [...parentTrail, it.title];
    flat.push({ id: it.id, title: it.title, url: it.url, trail });
    if (it.items) flat.push(...flattenMenuItems(it.items, trail));
  }
  return flat;
}

async function scanMenus() {
  const hits = [];
  let cursor = null;
  while (true) {
    const data = await gql(MENUS_QUERY, { cursor });
    const conn = data.menus;
    for (const { node: menu } of conn.edges) {
      const items = flattenMenuItems(menu.items);
      for (const it of items) {
        const text = `${it.title || ''} ${it.url || ''}`;
        hits.push(...searchTextForOutlet(text, 'menu', {
          menu: menu.handle,
          itemTitle: it.title,
          itemUrl: it.url,
          trail: it.trail.join(' › '),
        }));
      }
    }
    if (!conn.pageInfo.hasNextPage) break;
    cursor = conn.pageInfo.endCursor;
  }
  return hits;
}

async function scanPages() {
  const hits = [];
  let cursor = null;
  while (true) {
    const data = await gql(PAGES_QUERY, { cursor });
    const conn = data.pages;
    for (const { node } of conn.edges) {
      hits.push(...searchTextForOutlet(node.body, 'page', { handle: node.handle, title: node.title }));
    }
    if (!conn.pageInfo.hasNextPage) break;
    cursor = conn.pageInfo.endCursor;
  }
  return hits;
}

async function scanArticles() {
  const hits = [];
  let cursor = null;
  while (true) {
    const data = await gql(ARTICLES_QUERY, { cursor });
    const conn = data.articles;
    for (const { node } of conn.edges) {
      hits.push(...searchTextForOutlet(node.body, 'article', { handle: node.handle, title: node.title }));
    }
    if (!conn.pageInfo.hasNextPage) break;
    cursor = conn.pageInfo.endCursor;
  }
  return hits;
}

async function scanProductMetafieldsSample() {
  const hits = [];
  const data = await gql(PRODUCTS_FOR_METAFIELD_SAMPLE_QUERY, { first: PRODUCT_METAFIELD_SAMPLE });
  for (const { node: prod } of data.products.edges) {
    for (const { node: mf } of (prod.metafields?.edges ?? [])) {
      hits.push(...searchTextForOutlet(mf.value, 'product-metafield-sample', {
        productHandle: prod.handle,
        namespace: mf.namespace,
        key: mf.key,
      }));
    }
  }
  return hits;
}

async function scanShopReferences() {
  console.log('  Scanning shop metafields…');
  const shopMfHits = await scanShopMetafields();
  console.log(`    hits: ${shopMfHits.length}`);

  console.log('  Scanning menus…');
  const menuHits = await scanMenus();
  console.log(`    hits: ${menuHits.length}`);

  console.log('  Scanning pages…');
  const pageHits = await scanPages();
  console.log(`    hits: ${pageHits.length}`);

  console.log('  Scanning articles…');
  const articleHits = await scanArticles();
  console.log(`    hits: ${articleHits.length}`);

  console.log(`  Scanning product metafields (sample of ${PRODUCT_METAFIELD_SAMPLE} most-recently-updated)…`);
  const prodMfHits = await scanProductMetafieldsSample();
  console.log(`    hits: ${prodMfHits.length}`);

  return [...shopMfHits, ...menuHits, ...pageHits, ...articleHits, ...prodMfHits];
}

// -----------------------------------------------------------------------------
// Step 4 — collectionDelete
// -----------------------------------------------------------------------------

const COLLECTION_DELETE_MUTATION = /* GraphQL */ `
  mutation collectionDelete($input: CollectionDeleteInput!) {
    collectionDelete(input: $input) {
      deletedCollectionId
      userErrors { field message }
    }
  }
`;

async function executeDeletes(collections) {
  console.error('');
  console.error(`MODE: EXECUTE — about to delete ${collections.length} collections in ${PRE_DELETE_WAIT_MS / 1000} seconds. Ctrl+C to abort.`);
  console.error('');
  await sleep(PRE_DELETE_WAIT_MS);

  let deleted = 0;
  let errors = 0;
  let i = 0;
  for (const c of collections) {
    i++;
    try {
      const data = await gql(COLLECTION_DELETE_MUTATION, { input: { id: c.id } });
      const ue = data.collectionDelete.userErrors;
      if (ue && ue.length > 0) {
        errors++;
        console.error(`\n  ERR ${c.handle}: ${JSON.stringify(ue)}`);
      } else if (!data.collectionDelete.deletedCollectionId) {
        errors++;
        console.error(`\n  ERR ${c.handle}: no deletedCollectionId returned`);
      } else {
        deleted++;
      }
    } catch (e) {
      errors++;
      console.error(`\n  THROW ${c.handle}: ${e.message}`);
    }
    if (i % 5 === 0 || i === collections.length) {
      process.stdout.write(`\rDeleting: ${i}/${collections.length}  (deleted=${deleted}, errors=${errors})`);
    }
  }
  process.stdout.write('\n');
  return { deleted, errors };
}

// -----------------------------------------------------------------------------
// Main
// -----------------------------------------------------------------------------

function fmtCollectionsTable(collections) {
  const rows = collections.map((c) => ({
    handle: c.handle,
    title: c.title,
    productsCount: c.productsCount,
    kind: c.kind,
    publications: c.publications.join(', '),
  }));
  const lines = [];
  lines.push(`  ${'handle'.padEnd(40)} ${'productsCount'.padStart(13)}  ${'kind'.padEnd(8)} ${'publications'}`);
  lines.push(`  ${'-'.repeat(40)} ${'-'.repeat(13)}  ${'-'.repeat(8)} ${'-'.repeat(30)}`);
  for (const r of rows) {
    lines.push(`  ${r.handle.padEnd(40)} ${String(r.productsCount ?? '?').padStart(13)}  ${r.kind.padEnd(8)} ${r.publications}`);
  }
  return lines.join('\n');
}

(async () => {
  console.log(`Shop:    ${SHOPIFY_STORE_DOMAIN}`);
  console.log(`API:     ${API_VERSION}`);
  console.log(`Mode:    ${DRY_RUN ? 'DRY RUN (no changes)' : 'EXECUTE'}`);
  console.log('');

  console.log('Step 1/3: discover outlet-* collections…');
  const collections = await discoverOutletCollections();
  console.log(`  Found ${collections.length} outlet-* collections.`);
  console.log('');
  if (collections.length === 0) {
    console.log('Nothing to do. Exiting.');
    return;
  }
  console.log('── Inventory ──');
  console.log(fmtCollectionsTable(collections));
  console.log('');

  console.log('Step 2/3: scan for references to outlet-* in theme + shop…');
  console.log('  Scanning theme files locally…');
  const themeHits = await scanThemeFiles();
  console.log(`    hits: ${themeHits.length}`);
  const shopHits = await scanShopReferences();
  const allRefs = [...themeHits, ...shopHits];
  console.log('');

  await writeFile(PLAN_FILE, JSON.stringify({
    mode: DRY_RUN ? 'dry-run' : 'execute',
    collections,
    references: allRefs,
  }, null, 2));
  console.log(`Plan written to ${PLAN_FILE}.`);
  console.log('');

  if (allRefs.length > 0) {
    console.log('── References found ──');
    for (const r of allRefs) {
      const tail = r.path ? `${r.path}:${r.line}` : (r.itemUrl || r.handle || `${r.namespace || ''}/${r.key || ''}` || r.menu || '(unknown)');
      console.log(`  [${r.source}] ${tail}  match="${r.match}"  ctx: ${r.context}`);
    }
    console.log('');
    console.log(`Total references: ${allRefs.length}`);
    console.error('');
    console.error('References found. Manual review required. No collections deleted.');
    process.exit(1);
  }

  console.log('No references to outlet-* found in theme or shop.');
  console.log('');
  console.log('Step 3/3: deletion plan');
  console.log('');

  if (DRY_RUN) {
    console.log('── Plan (DRY RUN) ──');
    for (const c of collections) {
      console.log(`  [${c.handle}] would delete (productCount=${c.productsCount ?? '?'}, ${c.kind})`);
    }
    console.log('');
    console.log(`DRY RUN: would delete ${collections.length} collections. Set DRY_RUN=false to execute.`);
    return;
  }

  // Execute
  const result = await executeDeletes(collections);
  console.log('');
  console.log(`Deleted ${result.deleted} of ${collections.length} collections. Errors: ${result.errors}.`);
  if (result.errors > 0) process.exit(1);
})().catch((err) => {
  console.error('FATAL:', err);
  process.exit(1);
});
